+        thread = Thread.startVirtualThread(() -> {
+            started.countDown();
+            while (!done) {
+                LockSupport.park();
+            }
+        });
+        started.await();
+    }
+
+    @TearDown
+    public void shutdown() throws InterruptedException {
+        done = true;
+        LockSupport.unpark(thread);
+        thread.join();
+    }
+
+    @Benchmark
+    public StackTraceElement[] testGetStackTrace() {
+        return thread.getStackTrace();
+    }
+}

